open(f"{base}/app/page.tsx", "w").write("\"use client\";\nimport { useState, useRef, useEffect, useCallback } from \"react\";\nimport styles from \"./page.module.css\";\n\n/* \u2500\u2500 Types \u2500\u2500 */\ntype Msg  = { role: \"user\"|\"assistant\"; content: string };\ntype View = \"chat\"|\"tools\"|\"landing\";\ntype Tool = { id: string; label: string; icon: string; ph: string; crmField?: string };\ntype User = { userId: string; name: string; email: string; plan: string };\ntype AuthMode = \"signin\"|\"signup\";\n\n/* \u2500\u2500 Data \u2500\u2500 */\nconst TOOLS: Tool[] = [\n  { id:\"script_youtube\", label:\"YouTube Script\",  icon:\"\u25b6\", ph:\"e.g. How I grew to 100K subscribers\",  crmField:\"scripts\"  },\n  { id:\"script_reel\",    label:\"Reel Script\",     icon:\"\u26a1\", ph:\"e.g. 5 habits that changed my life\",   crmField:\"reels\"    },\n  { id:\"ideas\",          label:\"Content Ideas\",   icon:\"\ud83d\udca1\", ph:\"e.g. fitness for busy professionals\",  crmField:\"ideas\"    },\n  { id:\"captions\",       label:\"Captions\",        icon:\"\u270f\", ph:\"e.g. just launched my product\",        crmField:\"captions\" },\n  { id:\"hashtags\",       label:\"Hashtags\",        icon:\"#\",  ph:\"e.g. travel photography Bali\"                             },\n  { id:\"thumbnail\",      label:\"Thumbnail Text\",  icon:\"\ud83d\uddbc\", ph:\"e.g. I quit my job to be a creator\"                       },\n  { id:\"podcast\",        label:\"Podcast Outline\", icon:\"\ud83c\udf99\", ph:\"e.g. The future of AI content creation\"                   },\n  { id:\"bio\",            label:\"Creator Bio\",     icon:\"\ud83d\udc64\", ph:\"e.g. fitness & mindset creator, 500K on Instagram\"        },\n];\n\nconst PROMPTS = [\n  \"Write me a YouTube hook about morning routines\",\n  \"Give me 10 viral Reel ideas for a food creator\",\n  \"Write captions for my product launch post\",\n  \"Create a 60-second script for a productivity tip\",\n  \"Podcast outline: money mindset for Gen Z\",\n  \"Thumbnail ideas for a travel vlog in Tokyo\",\n];\n\nconst FEATURES = [\n  { icon:\"\u25b6\", title:\"YouTube Scripts\",  desc:\"Full scripts with hooks, timestamps, B-roll cues and CTAs \u2014 ready to film.\" },\n  { icon:\"\u26a1\", title:\"Reel Scripts\",     desc:\"60-second punchy scripts built for short-form. One idea per cut.\" },\n  { icon:\"\ud83d\udca1\", title:\"Content Ideas\",   desc:\"10 viral-ready ideas for any niche, ranked by scroll-stopping potential.\" },\n  { icon:\"\u270f\", title:\"Captions\",         desc:\"5 caption variations \u2014 short, story, educational, controversial, personal.\" },\n  { icon:\"#\",  title:\"Hashtag Strategy\",desc:\"Tiered hashtag sets: mega reach, mid-range visibility, niche conversions.\" },\n  { icon:\"\ud83d\uddbc\", title:\"Thumbnail Text\",  desc:\"Scroll-stopping text concepts with emotion, colour and expression direction.\" },\n  { icon:\"\ud83c\udf99\", title:\"Podcast Outlines\",desc:\"Cold open, segments, lightning round, outro \u2014 complete episode structure.\" },\n  { icon:\"\ud83d\udc64\", title:\"Creator Bios\",    desc:\"Platform-native bios for Instagram, YouTube, TikTok, Twitter and LinkedIn.\" },\n];\n\n/* \u2500\u2500 Markdown renderer \u2500\u2500 */\nfunction MD({ text }: { text: string }) {\n  const lines = text.split(\"\\n\");\n  const els: React.ReactNode[] = [];\n  let i = 0;\n  while (i < lines.length) {\n    const l = lines[i];\n    if (!l.trim()) { els.push(<br key={i}/>); i++; continue; }\n    if (l.startsWith(\"### \")) { els.push(<h3 key={i} className={styles.mdH3}>{l.slice(4)}</h3>); }\n    else if (l.startsWith(\"## \")) { els.push(<h2 key={i} className={styles.mdH2}>{l.slice(3)}</h2>); }\n    else if (/^\\*\\*[^*]+\\*\\*$/.test(l)) { els.push(<p key={i} className={styles.mdBold}>{l.slice(2,-2)}</p>); }\n    else if (l.startsWith(\"- \")||l.startsWith(\"\u2022 \")) {\n      const items:string[] = [];\n      while (i<lines.length && (lines[i].startsWith(\"- \")||lines[i].startsWith(\"\u2022 \"))) { items.push(lines[i].slice(2)); i++; }\n      els.push(<ul key={`u${i}`} className={styles.mdList}>{items.map((it,j)=><li key={j}>{fmt(it)}</li>)}</ul>);\n      continue;\n    } else { els.push(<p key={i} className={styles.mdP}>{fmt(l)}</p>); }\n    i++;\n  }\n  return <>{els}</>;\n}\nfunction fmt(t: string): React.ReactNode {\n  return t.split(/(\\*\\*[^*]+\\*\\*|\\*[^*]+\\*|`[^`]+`)/g).map((p,i)=>{\n    if (p.startsWith(\"**\")&&p.endsWith(\"**\")) return <strong key={i}>{p.slice(2,-2)}</strong>;\n    if (p.startsWith(\"*\")&&p.endsWith(\"*\"))   return <em key={i}>{p.slice(1,-1)}</em>;\n    if (p.startsWith(\"`\")&&p.endsWith(\"`\"))   return <code key={i} className={styles.icode}>{p.slice(1,-1)}</code>;\n    return p;\n  });\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   MAIN COMPONENT\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\nexport default function App() {\n  /* Auth */\n  const [user,     setUser]     = useState<User|null>(null);\n  const [authOpen, setAuthOpen] = useState(false);\n  const [authMode, setAuthMode] = useState<AuthMode>(\"signup\");\n  const [authName, setAuthName] = useState(\"\");\n  const [authEmail,setAuthEmail]= useState(\"\");\n  const [authPw,   setAuthPw]   = useState(\"\");\n  const [authErr,  setAuthErr]  = useState(\"\");\n  const [authLoad, setAuthLoad] = useState(false);\n\n  /* Chat modal */\n  const [chatOpen, setChatOpen] = useState(false);\n  const [msgs,     setMsgs]     = useState<Msg[]>([]);\n  const [input,    setInput]    = useState(\"\");\n  const [streaming,setStreaming]= useState(false);\n\n  /* Tools */\n  const [toolView, setToolView] = useState(false);\n  const [tool,     setTool]     = useState<Tool>(TOOLS[0]);\n  const [toolIn,   setToolIn]   = useState(\"\");\n  const [toolOut,  setToolOut]  = useState(\"\");\n  const [toolLoad, setToolLoad] = useState(false);\n  const [toolErr,  setToolErr]  = useState(\"\");\n\n  /* UI */\n  const [copied,   setCopied]   = useState<string|null>(null);\n  const [menuOpen, setMenuOpen] = useState(false);\n\n  const endRef   = useRef<HTMLDivElement>(null);\n  const inputRef = useRef<HTMLTextAreaElement>(null);\n\n  /* Bootstrap auth */\n  useEffect(() => {\n    fetch(\"/api/auth/me\").then(r=>r.json()).then(d=>{ if(d.user) setUser(d.user); }).catch(()=>{});\n  }, []);\n\n  useEffect(() => { endRef.current?.scrollIntoView({ behavior:\"smooth\" }); }, [msgs, streaming]);\n\n  useEffect(() => {\n    const ta = inputRef.current;\n    if (!ta) return;\n    ta.style.height = \"auto\";\n    ta.style.height = Math.min(ta.scrollHeight, 130) + \"px\";\n  }, [input]);\n\n  /* Lock body scroll when modal open */\n  useEffect(() => {\n    document.body.style.overflow = (chatOpen || authOpen) ? \"hidden\" : \"\";\n  }, [chatOpen, authOpen]);\n\n  /* \u2500\u2500 Auth \u2500\u2500 */\n  const handleAuth = async () => {\n    setAuthErr(\"\"); setAuthLoad(true);\n    try {\n      const body = authMode === \"signup\"\n        ? { name: authName, email: authEmail, password: authPw }\n        : { email: authEmail, password: authPw };\n      const r = await fetch(`/api/auth/${authMode}`, {\n        method:\"POST\", headers:{\"Content-Type\":\"application/json\"}, body:JSON.stringify(body),\n      });\n      const d = await r.json();\n      if (!r.ok) { setAuthErr(d.error || \"Error\"); return; }\n      setUser(d.user); setAuthOpen(false); setAuthName(\"\"); setAuthEmail(\"\"); setAuthPw(\"\");\n    } catch { setAuthErr(\"Network error. Try again.\"); }\n    finally { setAuthLoad(false); }\n  };\n\n  const handleSignOut = async () => {\n    await fetch(\"/api/auth/me\", { method:\"DELETE\" });\n    setUser(null); setMenuOpen(false);\n  };\n\n  /* \u2500\u2500 Chat \u2500\u2500 */\n  const openChat = (prompt?: string) => {\n    setChatOpen(true); setToolView(false);\n    if (prompt && msgs.length === 0) setTimeout(()=>sendMsg(prompt), 100);\n  };\n\n  const sendMsg = useCallback(async (content?: string) => {\n    const text = (content ?? input).trim();\n    if (!text || streaming) return;\n    const userMsg: Msg = { role:\"user\", content:text };\n    const next = [...msgs, userMsg];\n    setMsgs(next); setInput(\"\"); setStreaming(true);\n    setMsgs(p=>[...p, { role:\"assistant\", content:\"\" }]);\n    try {\n      const r = await fetch(\"/api/chat\", {\n        method:\"POST\", headers:{\"Content-Type\":\"application/json\"},\n        body:JSON.stringify({ messages:next }),\n      });\n      if (!r.ok || !r.body) throw new Error();\n      const reader  = r.body.getReader();\n      const decoder = new TextDecoder();\n      let buf = \"\";\n      while(true){\n        const { done, value } = await reader.read();\n        if (done) break;\n        buf += decoder.decode(value, { stream:true });\n        const lines = buf.split(\"\\n\"); buf = lines.pop()||\"\";\n        for(const line of lines){\n          if(!line.startsWith(\"data: \")) continue;\n          const data = line.slice(6);\n          if(data===\"[DONE]\") break;\n          try {\n            const { text:chunk } = JSON.parse(data);\n            if(chunk) setMsgs(p=>{\n              const u=[...p];\n              u[u.length-1]={...u[u.length-1],content:u[u.length-1].content+chunk};\n              return u;\n            });\n          } catch{}\n        }\n      }\n    } catch {\n      setMsgs(p=>{ const u=[...p]; u[u.length-1]={...u[u.length-1],content:\"Something went wrong. Check your API key in Vercel settings.\"}; return u; });\n    } finally { setStreaming(false); }\n  }, [input, msgs, streaming]);\n\n  const kd = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {\n    if (e.key===\"Enter\"&&!e.shiftKey){ e.preventDefault(); sendMsg(); }\n  };\n\n  /* \u2500\u2500 Tools \u2500\u2500 */\n  const runTool = async () => {\n    if (!toolIn.trim()||toolLoad) return;\n    setToolLoad(true); setToolOut(\"\"); setToolErr(\"\");\n    try {\n      const r = await fetch(\"/api/generate\", {\n        method:\"POST\", headers:{\"Content-Type\":\"application/json\"},\n        body:JSON.stringify({ tool:tool.id, input:toolIn.trim() }),\n      });\n      const d = await r.json();\n      if(!r.ok) throw new Error(d.error||\"Failed\");\n      setToolOut(d.result);\n    } catch(e){ setToolErr(e instanceof Error?e.message:\"Error\"); }\n    finally { setToolLoad(false); }\n  };\n\n  const copy = (text:string, id:string)=>{ navigator.clipboard.writeText(text); setCopied(id); setTimeout(()=>setCopied(null),2000); };\n\n  /* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n     RENDER\n  \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n  return (\n    <div className={styles.app}>\n\n      {/* \u2500\u2500 Background orbs \u2500\u2500 */}\n      <div className={styles.orb1}/>\n      <div className={styles.orb2}/>\n      <div className={styles.orb3}/>\n\n      {/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n          LANDING PAGE\n      \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */}\n      <nav className={styles.nav}>\n        <div className={styles.navLogo}>\n          <span className={styles.navLogoMark}>\u25c8</span>\n          <span className={styles.navLogoText}>SHANKH</span>\n        </div>\n        <div className={styles.navLinks}>\n          <button className={styles.navLink} onClick={()=>{ if(!chatOpen){ setChatOpen(true); setToolView(false); } }}>AI Chat</button>\n          <button className={styles.navLink} onClick={()=>{ setChatOpen(true); setToolView(true); }}>Tools</button>\n          {user ? (\n            <div className={styles.navUser}>\n              <button className={styles.navAvatarBtn} onClick={()=>setMenuOpen(v=>!v)}>\n                {user.name.charAt(0).toUpperCase()}\n              </button>\n              {menuOpen && (\n                <div className={styles.userMenu}>\n                  <p className={styles.userMenuName}>{user.name}</p>\n                  <p className={styles.userMenuEmail}>{user.email}</p>\n                  <div className={styles.userMenuDivider}/>\n                  <span className={styles.userMenuPlan}>{user.plan === \"free\" ? \"\u2713 Free Forever\" : \"\u2605 Standard\"}</span>\n                  <div className={styles.userMenuDivider}/>\n                  <button className={styles.userMenuSignOut} onClick={handleSignOut}>Sign out</button>\n                </div>\n              )}\n            </div>\n          ) : (\n            <>\n              <button className={styles.navSignIn} onClick={()=>{ setAuthMode(\"signin\"); setAuthOpen(true); }}>Sign in</button>\n              <button className={styles.navSignUp} onClick={()=>{ setAuthMode(\"signup\"); setAuthOpen(true); }}>Get started free</button>\n            </>\n          )}\n        </div>\n      </nav>\n\n      {/* Hero */}\n      <section className={styles.hero}>\n        <div className={styles.heroBadge}>\u2726 Free Forever Plan Available</div>\n        <h1 className={styles.heroTitle}>\n          Anything Creative<br/>\n          <span className={styles.heroGrad}>powered by SHANKH MEDIA</span>\n        </h1>\n        <p className={styles.heroSub}>\n          AI scripts, Reel ideas, captions, thumbnails, podcast outlines and more \u2014<br/>\n          everything a creator needs, in one place.\n        </p>\n        <div className={styles.heroCtas}>\n          <button className={styles.ctaPrimary} onClick={()=>{ if(!user){ setAuthMode(\"signup\"); setAuthOpen(true); } else openChat(); }}>\n            Start creating free\n          </button>\n          <button className={styles.ctaSecondary} onClick={()=>{ setChatOpen(true); setToolView(false); }}>\n            Try AI Chat \u2192\n          </button>\n        </div>\n        <div className={styles.heroStats}>\n          <div className={styles.heroStat}><span className={styles.heroStatNum}>8</span><span className={styles.heroStatLabel}>AI Tools</span></div>\n          <div className={styles.heroStatDiv}/>\n          <div className={styles.heroStat}><span className={styles.heroStatNum}>\u221e</span><span className={styles.heroStatLabel}>Free forever</span></div>\n          <div className={styles.heroStatDiv}/>\n          <div className={styles.heroStat}><span className={styles.heroStatNum}>0</span><span className={styles.heroStatLabel}>Credit card needed</span></div>\n        </div>\n      </section>\n\n      {/* Features grid */}\n      <section className={styles.features}>\n        <h2 className={styles.featTitle}>Every tool a creator needs</h2>\n        <div className={styles.featGrid}>\n          {FEATURES.map((f,i)=>(\n            <div key={i} className={styles.featCard} onClick={()=>{ const t=TOOLS[i]; if(t){ setTool(t); setToolIn(\"\"); setToolOut(\"\"); setChatOpen(true); setToolView(true); } }}>\n              <span className={styles.featIcon}>{f.icon}</span>\n              <h3 className={styles.featCardTitle}>{f.title}</h3>\n              <p className={styles.featCardDesc}>{f.desc}</p>\n              <span className={styles.featArrow}>\u2192</span>\n            </div>\n          ))}\n        </div>\n      </section>\n\n      {/* Pricing */}\n      <section className={styles.pricing}>\n        <h2 className={styles.pricingTitle}>Simple pricing</h2>\n        <div className={styles.pricingGrid}>\n          <div className={styles.pricingCard}>\n            <div className={styles.pricingPlan}>Free</div>\n            <div className={styles.pricingPrice}>\u20b90<span>/month</span></div>\n            <ul className={styles.pricingList}>\n              <li>\u2713 All 8 AI tools</li>\n              <li>\u2713 Unlimited AI chat</li>\n              <li>\u2713 Scripts, Reels, Ideas</li>\n              <li>\u2713 Captions & Hashtags</li>\n              <li>\u2713 Works on phone + web</li>\n              <li>\u2713 No credit card ever</li>\n            </ul>\n            <button className={styles.pricingBtn} onClick={()=>{ setAuthMode(\"signup\"); setAuthOpen(true); }}>\n              Get started free\n            </button>\n          </div>\n          <div className={`${styles.pricingCard} ${styles.pricingCardPro}`}>\n            <div className={styles.pricingBadge}>Coming soon</div>\n            <div className={styles.pricingPlan}>Standard</div>\n            <div className={styles.pricingPrice}>\u20b9299<span>/month</span></div>\n            <ul className={styles.pricingList}>\n              <li>\u2713 Everything in Free</li>\n              <li>\u2713 Priority AI responses</li>\n              <li>\u2713 Save scripts & ideas</li>\n              <li>\u2713 Export as PDF / doc</li>\n              <li>\u2713 Early access to new tools</li>\n              <li>\u2713 Creator community</li>\n            </ul>\n            <button className={styles.pricingBtnPro} disabled>Notify me</button>\n          </div>\n        </div>\n      </section>\n\n      {/* Footer */}\n      <footer className={styles.footer}>\n        <div className={styles.footerLogo}>\n          <span className={styles.navLogoMark}>\u25c8</span>\n          <span>SHANKH MEDIA</span>\n        </div>\n        <p className={styles.footerTag}>Anything Creative, powered by SHANKH MEDIA</p>\n        <p className={styles.footerCopy}>\u00a9 2025 SHANKH MEDIA. Built with \u2764 for creators everywhere.</p>\n      </footer>\n\n      {/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n          FLOATING MIC BUTTON\n      \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */}\n      {!chatOpen && (\n        <button className={styles.micBtn} onClick={()=>{ setChatOpen(true); setToolView(false); }} aria-label=\"Open SHANKH AI\">\n          <span className={styles.micRing1}/>\n          <span className={styles.micRing2}/>\n          <svg className={styles.micIcon} viewBox=\"0 0 24 24\" fill=\"none\">\n            <rect x=\"9\" y=\"2\" width=\"6\" height=\"11\" rx=\"3\" fill=\"white\"/>\n            <path d=\"M5 10a7 7 0 0014 0\" stroke=\"white\" strokeWidth=\"2\" strokeLinecap=\"round\"/>\n            <line x1=\"12\" y1=\"19\" x2=\"12\" y2=\"22\" stroke=\"white\" strokeWidth=\"2\" strokeLinecap=\"round\"/>\n            <line x1=\"8\" y1=\"22\" x2=\"16\" y2=\"22\" stroke=\"white\" strokeWidth=\"2\" strokeLinecap=\"round\"/>\n          </svg>\n        </button>\n      )}\n\n      {/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n          CHAT MODAL\n      \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */}\n      {chatOpen && (\n        <div className={styles.modal}>\n          {/* Modal header */}\n          <div className={styles.modalHeader}>\n            <div className={styles.modalLogo}>\n              <span className={styles.modalLogoMark}>\u25c8</span>\n              <div>\n                <div className={styles.modalLogoName}>SHANKH AI</div>\n                <div className={styles.modalLogoTag}>Anything Creative</div>\n              </div>\n            </div>\n            <div className={styles.modalTabs}>\n              <button className={`${styles.modalTab} ${!toolView?styles.modalTabActive:\"\"}`} onClick={()=>setToolView(false)}>\n                Chat\n              </button>\n              <button className={`${styles.modalTab} ${toolView?styles.modalTabActive:\"\"}`} onClick={()=>setToolView(true)}>\n                Tools\n              </button>\n            </div>\n            <button className={styles.modalClose} onClick={()=>setChatOpen(false)}>\u2715</button>\n          </div>\n\n          {/* \u2500\u2500 Chat panel \u2500\u2500 */}\n          {!toolView && (\n            <div className={styles.chatPanel}>\n              {msgs.length === 0 ? (\n                <div className={styles.chatWelcome}>\n                  <div className={styles.cwOrb}>\u25c8</div>\n                  <h2 className={styles.cwTitle}>What are we creating today?</h2>\n                  <p className={styles.cwSub}>Scripts \u00b7 Ideas \u00b7 Captions \u00b7 Strategy \u00b7 and more</p>\n                  <div className={styles.cwChips}>\n                    {PROMPTS.map((p,i)=>(\n                      <button key={i} className={styles.cwChip} onClick={()=>sendMsg(p)}>{p}</button>\n                    ))}\n                  </div>\n                </div>\n              ) : (\n                <div className={styles.chatMsgs}>\n                  {msgs.map((m,i)=>(\n                    <div key={i} className={`${styles.chatMsg} ${m.role===\"user\"?styles.chatMsgUser:styles.chatMsgAI}`}>\n                      {m.role===\"assistant\" && <div className={styles.aiAvatar}>\u25c8</div>}\n                      <div className={styles.msgBubble}>\n                        {m.role===\"assistant\"\n                          ? <div className={styles.mdWrap}>\n                              {m.content\n                                ? <MD text={m.content}/>\n                                : streaming&&i===msgs.length-1\n                                  ? <div className={styles.dots}><span/><span/><span/></div>\n                                  : null}\n                            </div>\n                          : <p>{m.content}</p>}\n                      </div>\n                      {m.role===\"assistant\"&&m.content&&(\n                        <button className={styles.copyBtn} onClick={()=>copy(m.content,`m${i}`)}>\n                          {copied===`m${i}`?\"\u2713\":\"\u2398\"}\n                        </button>\n                      )}\n                    </div>\n                  ))}\n                  <div ref={endRef}/>\n                </div>\n              )}\n\n              <div className={styles.chatInput}>\n                <div className={`${styles.inputWrap} ${streaming?styles.inputWrapActive:\"\"}`}>\n                  <textarea\n                    ref={inputRef}\n                    className={styles.textarea}\n                    value={input}\n                    onChange={e=>setInput(e.target.value)}\n                    onKeyDown={kd}\n                    placeholder=\"Ask SHANKH AI anything creative\u2026\"\n                    rows={1}\n                    disabled={streaming}\n                  />\n                  <button\n                    className={`${styles.sendBtn} ${(!input.trim()||streaming)?styles.sendBtnOff:\"\"}`}\n                    onClick={()=>sendMsg()}\n                    disabled={!input.trim()||streaming}\n                  >\n                    {streaming ? <span className={styles.spinner}/> : \"\u2191\"}\n                  </button>\n                </div>\n                <p className={styles.inputHint}>AI content \u2014 always review before publishing.</p>\n              </div>\n            </div>\n          )}\n\n          {/* \u2500\u2500 Tools panel \u2500\u2500 */}\n          {toolView && (\n            <div className={styles.toolsPanel}>\n              {/* Tool selector */}\n              <div className={styles.toolScroll}>\n                {TOOLS.map(t=>(\n                  <button key={t.id}\n                    className={`${styles.toolChip} ${tool.id===t.id?styles.toolChipActive:\"\"}`}\n                    onClick={()=>{ setTool(t); setToolIn(\"\"); setToolOut(\"\"); setToolErr(\"\"); }}\n                  >\n                    <span>{t.icon}</span><span>{t.label}</span>\n                  </button>\n                ))}\n              </div>\n\n              <div className={styles.toolBody}>\n                <label className={styles.toolLabel}>{tool.icon} {tool.label}</label>\n                <textarea\n                  className={styles.toolTextarea}\n                  value={toolIn}\n                  onChange={e=>setToolIn(e.target.value)}\n                  placeholder={tool.ph}\n                  rows={3}\n                />\n                <button\n                  className={`${styles.genBtn} ${toolLoad?styles.genBtnLoad:\"\"}`}\n                  onClick={runTool}\n                  disabled={!toolIn.trim()||toolLoad}\n                >\n                  {toolLoad ? <><span className={styles.spinner}/> Generating\u2026</> : `Generate ${tool.label}`}\n                </button>\n\n                {toolErr && <div className={styles.toolErr}>\u26a0 {toolErr}</div>}\n\n                {toolOut && (\n                  <div className={styles.toolResult}>\n                    <div className={styles.toolResultHdr}>\n                      <span>Result</span>\n                      <button className={styles.copyAllBtn} onClick={()=>copy(toolOut,\"res\")}>\n                        {copied===\"res\"?\"\u2713 Copied\":\"\u2398 Copy all\"}\n                      </button>\n                    </div>\n                    <div className={styles.mdWrap}><MD text={toolOut}/></div>\n                  </div>\n                )}\n              </div>\n            </div>\n          )}\n        </div>\n      )}\n\n      {/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n          AUTH MODAL\n      \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */}\n      {authOpen && (\n        <div className={styles.authOverlay} onClick={()=>setAuthOpen(false)}>\n          <div className={styles.authModal} onClick={e=>e.stopPropagation()}>\n            <button className={styles.authClose} onClick={()=>setAuthOpen(false)}>\u2715</button>\n\n            <div className={styles.authLogo}>\n              <span className={styles.navLogoMark}>\u25c8</span>\n              <span className={styles.authLogoText}>SHANKH Creative OS</span>\n            </div>\n\n            <h2 className={styles.authTitle}>\n              {authMode===\"signup\" ? \"Create your free account\" : \"Welcome back\"}\n            </h2>\n            <p className={styles.authSub}>\n              {authMode===\"signup\" ? \"Free forever. No credit card needed.\" : \"Sign in to continue creating.\"}\n            </p>\n\n            <div className={styles.authForm}>\n              {authMode===\"signup\" && (\n                <input\n                  className={styles.authInput}\n                  type=\"text\"\n                  placeholder=\"Your name\"\n                  value={authName}\n                  onChange={e=>setAuthName(e.target.value)}\n                />\n              )}\n              <input\n                className={styles.authInput}\n                type=\"email\"\n                placeholder=\"Email address\"\n                value={authEmail}\n                onChange={e=>setAuthEmail(e.target.value)}\n              />\n              <input\n                className={styles.authInput}\n                type=\"password\"\n                placeholder=\"Password (min 6 chars)\"\n                value={authPw}\n                onChange={e=>setAuthPw(e.target.value)}\n                onKeyDown={e=>{ if(e.key===\"Enter\") handleAuth(); }}\n              />\n              {authErr && <p className={styles.authErr}>{authErr}</p>}\n              <button\n                className={`${styles.authBtn} ${authLoad?styles.authBtnLoad:\"\"}`}\n                onClick={handleAuth}\n                disabled={authLoad}\n              >\n                {authLoad ? <span className={styles.spinner}/> : authMode===\"signup\" ? \"Create account\" : \"Sign in\"}\n              </button>\n            </div>\n\n            <p className={styles.authSwitch}>\n              {authMode===\"signup\" ? \"Already have an account? \" : \"Don't have an account? \"}\n              <button className={styles.authSwitchBtn} onClick={()=>{ setAuthMode(authMode===\"signup\"?\"signin\":\"signup\"); setAuthErr(\"\"); }}>\n                {authMode===\"signup\" ? \"Sign in\" : \"Sign up free\"}\n              </button>\n            </p>\n          </div>\n        </div>\n      )}\n    </div>\n  );\n}\n")
print("wrote app/page.tsx")
os.makedirs(f"{base}/app", exist_ok=True)
open(f"{base}/app/page.module.css", "w").write("/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   BASE\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.app {\n  min-height: 100dvh;\n  background: #000;\n  color: #fff;\n  position: relative;\n  overflow-x: hidden;\n}\n\n/* \u2500\u2500 Ambient orbs \u2500\u2500 */\n.orb1,.orb2,.orb3 {\n  position: fixed; border-radius: 50%;\n  pointer-events: none; z-index: 0;\n  filter: blur(120px); opacity: 0.18;\n  animation: orbFloat 18s ease-in-out infinite;\n}\n.orb1 { width:600px; height:600px; background:radial-gradient(circle,#a855f7,transparent); top:-200px; left:-200px; animation-delay:0s; }\n.orb2 { width:500px; height:500px; background:radial-gradient(circle,#ec4899,transparent); bottom:-150px; right:-150px; animation-delay:-6s; }\n.orb3 { width:400px; height:400px; background:radial-gradient(circle,#f97316,transparent); top:40%; left:40%; animation-delay:-12s; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   NAV\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.nav {\n  position: fixed; top: 0; left: 0; right: 0; z-index: 100;\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 16px 32px;\n  background: rgba(0,0,0,0.6);\n  backdrop-filter: blur(24px) saturate(180%);\n  -webkit-backdrop-filter: blur(24px) saturate(180%);\n  border-bottom: 1px solid rgba(255,255,255,0.07);\n}\n.navLogo { display:flex; align-items:center; gap:8px; }\n.navLogoMark {\n  font-size: 22px;\n  background: var(--grad);\n  background-size: 300% 300%;\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n  animation: gradFlow 6s ease infinite;\n}\n.navLogoText { font-size:16px; font-weight:700; letter-spacing:-0.01em; }\n.navLinks { display:flex; align-items:center; gap:8px; }\n.navLink { font-size:14px; color:rgba(255,255,255,0.6); padding:7px 14px; border-radius:8px; transition:color 0.15s; }\n.navLink:hover { color:#fff; }\n.navSignIn { font-size:14px; color:rgba(255,255,255,0.7); padding:8px 16px; border-radius:10px; border:1px solid rgba(255,255,255,0.12); transition:all 0.15s; }\n.navSignIn:hover { border-color:rgba(255,255,255,0.3); color:#fff; }\n.navSignUp {\n  font-size:14px; font-weight:600; color:#000;\n  padding:8px 18px; border-radius:10px;\n  background: #fff;\n  transition: all 0.2s;\n}\n.navSignUp:hover { background:rgba(255,255,255,0.85); transform:translateY(-1px); box-shadow:0 4px 20px rgba(255,255,255,0.2); }\n\n/* User menu */\n.navUser { position:relative; }\n.navAvatarBtn {\n  width:34px; height:34px; border-radius:50%;\n  background: var(--grad); background-size:300% 300%;\n  animation: gradFlow 6s ease infinite;\n  color:#fff; font-size:14px; font-weight:700;\n  display:flex; align-items:center; justify-content:center;\n}\n.userMenu {\n  position:absolute; top:44px; right:0; width:210px;\n  background:#111; border:1px solid rgba(255,255,255,0.1);\n  border-radius:14px; padding:12px;\n  box-shadow:0 20px 60px rgba(0,0,0,0.8);\n  animation: fadeIn 0.15s ease;\n}\n.userMenuName { font-size:13px; font-weight:600; margin-bottom:2px; }\n.userMenuEmail { font-size:11px; color:rgba(255,255,255,0.45); }\n.userMenuDivider { height:1px; background:rgba(255,255,255,0.08); margin:10px 0; }\n.userMenuPlan { font-size:11px; color:#a855f7; font-weight:500; }\n.userMenuSignOut { font-size:13px; color:rgba(255,255,255,0.5); padding:6px 0; width:100%; text-align:left; transition:color 0.15s; }\n.userMenuSignOut:hover { color:#fff; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   HERO\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.hero {\n  position:relative; z-index:1;\n  display:flex; flex-direction:column; align-items:center;\n  text-align:center;\n  padding: 160px 24px 100px;\n  min-height:100dvh;\n}\n.heroBadge {\n  display:inline-flex; align-items:center; gap:6px;\n  font-size:12px; font-weight:500; letter-spacing:0.04em;\n  color:rgba(255,255,255,0.5);\n  border:1px solid rgba(255,255,255,0.1);\n  padding:6px 16px; border-radius:20px;\n  margin-bottom:32px;\n  animation: fadeUp 0.6s ease;\n  background:rgba(255,255,255,0.04);\n}\n.heroTitle {\n  font-size: clamp(38px, 7vw, 80px);\n  font-weight: 800;\n  letter-spacing: -0.04em;\n  line-height: 1.08;\n  margin-bottom: 24px;\n  animation: fadeUp 0.6s ease 0.1s both;\n}\n.heroGrad {\n  background: var(--grad);\n  background-size: 300% 300%;\n  -webkit-background-clip: text;\n  -webkit-text-fill-color: transparent;\n  background-clip: text;\n  animation: gradFlow 5s ease infinite;\n  display: block;\n}\n.heroSub {\n  font-size: clamp(15px, 2.5vw, 19px);\n  color: rgba(255,255,255,0.55);\n  line-height: 1.65;\n  max-width: 560px;\n  margin-bottom: 40px;\n  animation: fadeUp 0.6s ease 0.2s both;\n  font-weight: 400;\n}\n.heroCtas {\n  display:flex; gap:12px; flex-wrap:wrap; justify-content:center;\n  margin-bottom:48px;\n  animation: fadeUp 0.6s ease 0.3s both;\n}\n.ctaPrimary {\n  background: var(--grad); background-size:300% 300%;\n  animation: gradFlow 5s ease infinite;\n  color:#fff; font-size:16px; font-weight:700;\n  padding:15px 32px; border-radius:14px;\n  transition:all 0.2s;\n  position:relative; overflow:hidden;\n}\n.ctaPrimary:hover { transform:translateY(-2px); box-shadow:0 8px 40px rgba(168,85,247,0.5); }\n.ctaSecondary {\n  background:rgba(255,255,255,0.06); color:#fff;\n  font-size:15px; font-weight:500;\n  padding:15px 28px; border-radius:14px;\n  border:1px solid rgba(255,255,255,0.12);\n  transition:all 0.2s;\n}\n.ctaSecondary:hover { background:rgba(255,255,255,0.1); border-color:rgba(255,255,255,0.25); }\n.heroStats {\n  display:flex; align-items:center; gap:32px;\n  animation: fadeUp 0.6s ease 0.4s both;\n}\n.heroStat { display:flex; flex-direction:column; align-items:center; gap:2px; }\n.heroStatNum {\n  font-size:28px; font-weight:800; letter-spacing:-0.03em;\n  background:var(--grad); background-size:300% 300%;\n  -webkit-background-clip:text; -webkit-text-fill-color:transparent;\n  background-clip:text; animation:gradFlow 5s ease infinite;\n}\n.heroStatLabel { font-size:11px; color:rgba(255,255,255,0.4); letter-spacing:0.04em; }\n.heroStatDiv { width:1px; height:32px; background:rgba(255,255,255,0.08); }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   FEATURES\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.features {\n  position:relative; z-index:1;\n  padding:80px 24px 100px;\n  max-width:1100px; margin:0 auto;\n}\n.featTitle {\n  font-size:clamp(28px,4vw,42px); font-weight:800;\n  letter-spacing:-0.03em; text-align:center;\n  margin-bottom:48px;\n}\n.featGrid {\n  display:grid;\n  grid-template-columns:repeat(auto-fill,minmax(240px,1fr));\n  gap:16px;\n}\n.featCard {\n  background:rgba(255,255,255,0.03);\n  border:1px solid rgba(255,255,255,0.07);\n  border-radius:20px; padding:24px;\n  cursor:pointer;\n  transition:all 0.25s cubic-bezier(0.25,0.46,0.45,0.94);\n  position:relative; overflow:hidden;\n  display:flex; flex-direction:column; gap:8px;\n}\n.featCard::before {\n  content:''; position:absolute; inset:0;\n  background:var(--grad); background-size:300% 300%;\n  animation:gradFlow 5s ease infinite;\n  opacity:0; transition:opacity 0.3s;\n  border-radius:20px;\n}\n.featCard:hover { transform:translateY(-4px); border-color:rgba(168,85,247,0.4); box-shadow:0 12px 40px rgba(168,85,247,0.15); }\n.featCard:hover::before { opacity:0.06; }\n.featIcon { font-size:22px; position:relative; z-index:1; }\n.featCardTitle { font-size:15px; font-weight:700; position:relative; z-index:1; }\n.featCardDesc { font-size:13px; color:rgba(255,255,255,0.5); line-height:1.55; position:relative; z-index:1; flex:1; }\n.featArrow { font-size:16px; color:rgba(255,255,255,0.2); align-self:flex-end; transition:color 0.15s; position:relative; z-index:1; }\n.featCard:hover .featArrow { color:rgba(168,85,247,0.8); }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   PRICING\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.pricing {\n  position:relative; z-index:1;\n  padding:80px 24px 120px;\n  max-width:800px; margin:0 auto;\n}\n.pricingTitle {\n  font-size:clamp(28px,4vw,42px); font-weight:800;\n  letter-spacing:-0.03em; text-align:center; margin-bottom:48px;\n}\n.pricingGrid { display:grid; grid-template-columns:1fr 1fr; gap:20px; }\n.pricingCard {\n  background:rgba(255,255,255,0.03);\n  border:1px solid rgba(255,255,255,0.08);\n  border-radius:24px; padding:32px;\n  position:relative;\n}\n.pricingCardPro {\n  background:rgba(168,85,247,0.06);\n  border-color:rgba(168,85,247,0.3);\n  box-shadow:0 0 60px rgba(168,85,247,0.1);\n}\n.pricingBadge {\n  position:absolute; top:16px; right:16px;\n  font-size:10px; font-weight:600; letter-spacing:0.06em;\n  background:rgba(168,85,247,0.2); color:#a855f7;\n  padding:4px 10px; border-radius:20px;\n}\n.pricingPlan { font-size:14px; font-weight:600; color:rgba(255,255,255,0.5); margin-bottom:8px; text-transform:uppercase; letter-spacing:0.06em; }\n.pricingPrice { font-size:40px; font-weight:800; letter-spacing:-0.04em; margin-bottom:24px; }\n.pricingPrice span { font-size:16px; font-weight:400; color:rgba(255,255,255,0.4); }\n.pricingList { list-style:none; display:flex; flex-direction:column; gap:10px; margin-bottom:28px; }\n.pricingList li { font-size:14px; color:rgba(255,255,255,0.65); }\n.pricingBtn {\n  width:100%; padding:13px; border-radius:12px;\n  background:#fff; color:#000; font-size:14px; font-weight:700;\n  transition:all 0.2s;\n}\n.pricingBtn:hover { background:rgba(255,255,255,0.9); transform:translateY(-1px); }\n.pricingBtnPro {\n  width:100%; padding:13px; border-radius:12px;\n  background:rgba(168,85,247,0.2); color:rgba(255,255,255,0.4);\n  font-size:14px; font-weight:700; cursor:not-allowed;\n  border:1px solid rgba(168,85,247,0.3);\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   FOOTER\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.footer {\n  position:relative; z-index:1;\n  border-top:1px solid rgba(255,255,255,0.06);\n  padding:40px 32px;\n  display:flex; flex-direction:column; align-items:center; gap:8px;\n  text-align:center;\n}\n.footerLogo { display:flex; align-items:center; gap:8px; font-weight:700; font-size:16px; }\n.footerTag { font-size:13px; color:rgba(255,255,255,0.35); }\n.footerCopy { font-size:12px; color:rgba(255,255,255,0.2); }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   FLOATING MIC BUTTON\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.micBtn {\n  position: fixed; bottom:28px; right:28px; z-index:200;\n  width: 64px; height: 64px; border-radius: 50%;\n  background: var(--grad); background-size:300% 300%;\n  animation: gradFlow 4s ease infinite, pulseGlow 3s ease-in-out infinite;\n  display: flex; align-items: center; justify-content: center;\n  transition: transform 0.2s cubic-bezier(0.34,1.56,0.64,1);\n}\n.micBtn:hover { transform:scale(1.12); }\n.micBtn:active { transform:scale(0.95); }\n.micRing1,.micRing2 {\n  position:absolute; inset:-2px; border-radius:50%;\n  background:var(--grad); background-size:300% 300%;\n  animation:gradFlow 4s ease infinite, micRing 2.5s ease-out infinite;\n  opacity:0.6;\n}\n.micRing2 { animation-delay:1.25s; }\n.micIcon { width:28px; height:28px; position:relative; z-index:1; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   CHAT MODAL \u2014 full screen\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.modal {\n  position: fixed; inset:0; z-index:500;\n  background:#000;\n  display:flex; flex-direction:column;\n  animation: fadeIn 0.2s ease;\n}\n\n.modalHeader {\n  display:flex; align-items:center; gap:12px;\n  padding:14px 20px;\n  background:rgba(255,255,255,0.03);\n  border-bottom:1px solid rgba(255,255,255,0.07);\n  flex-shrink:0;\n}\n.modalLogo { display:flex; align-items:center; gap:10px; }\n.modalLogoMark {\n  font-size:24px;\n  background:var(--grad); background-size:300% 300%;\n  -webkit-background-clip:text; -webkit-text-fill-color:transparent;\n  background-clip:text; animation:gradFlow 5s ease infinite;\n}\n.modalLogoName { font-size:15px; font-weight:700; line-height:1.2; }\n.modalLogoTag { font-size:10px; color:rgba(255,255,255,0.35); letter-spacing:0.04em; }\n.modalTabs { display:flex; gap:4px; margin-left:auto; }\n.modalTab {\n  font-size:13px; font-weight:500; color:rgba(255,255,255,0.4);\n  padding:7px 16px; border-radius:8px;\n  transition:all 0.15s;\n  border:1px solid transparent;\n}\n.modalTab:hover { color:#fff; background:rgba(255,255,255,0.06); }\n.modalTabActive { color:#fff; background:rgba(255,255,255,0.1); border-color:rgba(255,255,255,0.12); }\n.modalClose {\n  font-size:18px; color:rgba(255,255,255,0.4);\n  padding:8px; border-radius:8px;\n  transition:all 0.15s; margin-left:8px;\n}\n.modalClose:hover { color:#fff; background:rgba(255,255,255,0.08); }\n\n/* \u2500\u2500 Chat panel \u2500\u2500 */\n.chatPanel { flex:1; display:flex; flex-direction:column; overflow:hidden; }\n.chatWelcome {\n  flex:1; display:flex; flex-direction:column; align-items:center; justify-content:center;\n  padding:40px 24px; text-align:center;\n}\n.cwOrb {\n  font-size:52px; margin-bottom:20px;\n  background:var(--grad); background-size:300% 300%;\n  -webkit-background-clip:text; -webkit-text-fill-color:transparent;\n  background-clip:text; animation:gradFlow 5s ease infinite, float 6s ease-in-out infinite;\n  display:block;\n}\n.cwTitle { font-size:clamp(22px,4vw,34px); font-weight:800; letter-spacing:-0.03em; margin-bottom:10px; }\n.cwSub { font-size:15px; color:rgba(255,255,255,0.45); margin-bottom:32px; }\n.cwChips { display:grid; grid-template-columns:1fr 1fr; gap:8px; width:100%; max-width:560px; }\n.cwChip {\n  background:rgba(255,255,255,0.04);\n  border:1px solid rgba(255,255,255,0.08);\n  border-radius:14px; padding:14px 16px;\n  font-size:13px; color:rgba(255,255,255,0.6);\n  text-align:left; line-height:1.4;\n  transition:all 0.2s cubic-bezier(0.25,0.46,0.45,0.94);\n}\n.cwChip:hover {\n  background:rgba(255,255,255,0.07); color:#fff;\n  border-color:rgba(168,85,247,0.4);\n  transform:translateY(-2px);\n  box-shadow:0 4px 20px rgba(168,85,247,0.12);\n}\n\n.chatMsgs {\n  flex:1; overflow-y:auto; padding:20px;\n  display:flex; flex-direction:column; gap:18px;\n}\n.chatMsg { display:flex; gap:10px; align-items:flex-start; animation:fadeIn 0.2s ease; }\n.chatMsgUser { flex-direction:row-reverse; }\n.aiAvatar {\n  width:32px; height:32px; border-radius:50%; flex-shrink:0;\n  background:var(--grad); background-size:300% 300%;\n  animation:gradFlow 5s ease infinite;\n  display:flex; align-items:center; justify-content:center;\n  font-size:14px; color:#fff;\n}\n.msgBubble {\n  max-width:72%; padding:12px 16px;\n  border-radius:4px 18px 18px 18px;\n  background:rgba(255,255,255,0.06);\n  border:1px solid rgba(255,255,255,0.08);\n  font-size:14.5px; line-height:1.65; color:#fff;\n}\n.chatMsgUser .msgBubble {\n  background:var(--grad2);\n  border:none; color:#fff;\n  border-radius:18px 18px 4px 18px;\n  box-shadow:0 4px 20px rgba(168,85,247,0.3);\n}\n.dots { display:flex; gap:5px; padding:4px 0; }\n.dots span { width:7px; height:7px; border-radius:50%; background:rgba(255,255,255,0.3); animation:pulse 1.3s ease infinite; }\n.dots span:nth-child(2) { animation-delay:0.18s; }\n.dots span:nth-child(3) { animation-delay:0.36s; }\n.copyBtn {\n  opacity:0; font-size:14px; color:rgba(255,255,255,0.3);\n  padding:5px 7px; border-radius:7px;\n  transition:all 0.15s; margin-top:4px; flex-shrink:0;\n  background:rgba(255,255,255,0.05);\n  border:1px solid rgba(255,255,255,0.08);\n}\n.chatMsg:hover .copyBtn { opacity:1; }\n.copyBtn:hover { color:#fff; }\n\n/* \u2500\u2500 Chat input \u2500\u2500 */\n.chatInput { padding:14px 20px 18px; border-top:1px solid rgba(255,255,255,0.07); flex-shrink:0; }\n.inputWrap {\n  display:flex; align-items:flex-end; gap:10px;\n  background:rgba(255,255,255,0.05);\n  border:1px solid rgba(255,255,255,0.1);\n  border-radius:20px; padding:10px 10px 10px 18px;\n  transition:border-color 0.2s, box-shadow 0.2s;\n}\n.inputWrapActive, .inputWrap:focus-within {\n  border-color:rgba(168,85,247,0.5);\n  box-shadow:0 0 0 3px rgba(168,85,247,0.1);\n  animation:borderGlow 3s ease-in-out infinite;\n}\n.textarea {\n  flex:1; background:transparent; border:none; outline:none;\n  color:#fff; font-size:15px; line-height:1.5;\n  resize:none; min-height:22px; max-height:130px;\n  overflow-y:auto; letter-spacing:-0.01em;\n}\n.textarea::placeholder { color:rgba(255,255,255,0.28); }\n.textarea:disabled { opacity:0.5; }\n.sendBtn {\n  width:36px; height:36px; border-radius:50%;\n  background:var(--grad); background-size:300% 300%;\n  animation:gradFlow 5s ease infinite;\n  color:#fff; font-size:16px; font-weight:700;\n  display:flex; align-items:center; justify-content:center;\n  transition:all 0.2s;\n}\n.sendBtn:hover:not(.sendBtnOff) { transform:scale(1.08); box-shadow:0 4px 16px rgba(168,85,247,0.5); }\n.sendBtnOff { background:rgba(255,255,255,0.1)!important; animation:none!important; cursor:default; }\n.inputHint { font-size:10.5px; color:rgba(255,255,255,0.2); text-align:center; margin-top:8px; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   TOOLS PANEL\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.toolsPanel { flex:1; display:flex; flex-direction:column; overflow:hidden; }\n.toolScroll {\n  display:flex; gap:6px; padding:14px 20px;\n  overflow-x:auto; scrollbar-width:none; flex-shrink:0;\n  border-bottom:1px solid rgba(255,255,255,0.07);\n}\n.toolScroll::-webkit-scrollbar { display:none; }\n.toolChip {\n  display:flex; align-items:center; gap:5px;\n  padding:8px 16px; border-radius:20px;\n  font-size:13px; font-weight:400;\n  color:rgba(255,255,255,0.5);\n  border:1px solid rgba(255,255,255,0.08);\n  white-space:nowrap;\n  background:rgba(255,255,255,0.03);\n  transition:all 0.18s;\n}\n.toolChip:hover { color:#fff; border-color:rgba(255,255,255,0.2); }\n.toolChipActive {\n  background:var(--grad)!important; background-size:300% 300%!important;\n  animation:gradFlow 5s ease infinite!important;\n  color:#fff!important; border-color:transparent!important;\n  box-shadow:0 4px 16px rgba(168,85,247,0.35)!important;\n}\n.toolBody {\n  flex:1; overflow-y:auto; padding:20px;\n  display:flex; flex-direction:column; gap:14px;\n}\n.toolLabel { font-size:14px; font-weight:600; color:rgba(255,255,255,0.7); }\n.toolTextarea {\n  background:rgba(255,255,255,0.05);\n  border:1px solid rgba(255,255,255,0.1);\n  border-radius:14px; padding:14px 16px;\n  color:#fff; font-size:15px; line-height:1.5;\n  resize:vertical; min-height:90px; outline:none;\n  transition:border-color 0.2s, box-shadow 0.2s; width:100%;\n  letter-spacing:-0.01em;\n}\n.toolTextarea:focus {\n  border-color:rgba(168,85,247,0.5);\n  box-shadow:0 0 0 3px rgba(168,85,247,0.1);\n}\n.toolTextarea::placeholder { color:rgba(255,255,255,0.22); }\n.genBtn {\n  background:var(--grad); background-size:300% 300%;\n  animation:gradFlow 5s ease infinite;\n  color:#fff; font-size:15px; font-weight:700;\n  padding:13px 26px; border-radius:12px;\n  display:flex; align-items:center; gap:8px;\n  justify-content:center; align-self:flex-start;\n  transition:all 0.2s; letter-spacing:-0.01em;\n}\n.genBtn:hover:not(:disabled) { transform:translateY(-2px); box-shadow:0 8px 30px rgba(168,85,247,0.45); }\n.genBtn:disabled { opacity:0.4; cursor:default; transform:none; }\n.genBtnLoad { background:rgba(255,255,255,0.1)!important; animation:none!important; }\n.toolErr {\n  background:rgba(255,59,48,0.08); border:1px solid rgba(255,59,48,0.25);\n  border-radius:12px; padding:13px 15px;\n  font-size:13.5px; color:#ff3b30;\n}\n.toolResult {\n  background:rgba(255,255,255,0.04);\n  border:1px solid rgba(255,255,255,0.08);\n  border-radius:16px; overflow:hidden;\n  animation:popIn 0.25s ease;\n}\n.toolResultHdr {\n  display:flex; align-items:center; justify-content:space-between;\n  padding:12px 16px;\n  border-bottom:1px solid rgba(255,255,255,0.07);\n  background:rgba(255,255,255,0.03);\n}\n.toolResultHdr span { font-size:11px; font-weight:600; color:rgba(255,255,255,0.3); letter-spacing:0.08em; text-transform:uppercase; }\n.copyAllBtn { font-size:13px; color:rgba(255,255,255,0.5); padding:5px 10px; border-radius:8px; transition:all 0.15s; }\n.copyAllBtn:hover { color:#fff; background:rgba(255,255,255,0.08); }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   MARKDOWN\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.mdWrap {\n  padding:14px 16px; font-size:14.5px; line-height:1.7;\n  color:rgba(255,255,255,0.88); letter-spacing:-0.01em;\n}\n.toolResult .mdWrap { padding:16px; }\n.chatMsgUser .mdWrap { padding:0; }\n.msgBubble .mdWrap { padding:0; }\n.mdH2 { font-size:15px; font-weight:700; color:#fff; margin:14px 0 5px; padding-bottom:5px; border-bottom:1px solid rgba(255,255,255,0.08); letter-spacing:-0.015em; }\n.mdH3 { font-size:13.5px; font-weight:600; color:rgba(168,85,247,0.9); margin:10px 0 3px; }\n.mdBold { font-weight:700; color:#fff; margin:7px 0 2px; }\n.mdP { margin:4px 0; }\n.mdList { margin:5px 0; padding-left:18px; display:flex; flex-direction:column; gap:3px; }\n.mdList li { line-height:1.6; }\n.icode { background:rgba(168,85,247,0.15); color:#c084fc; padding:1px 6px; border-radius:5px; font-family:var(--mono); font-size:12.5px; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   AUTH MODAL\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.authOverlay {\n  position:fixed; inset:0; z-index:600;\n  background:rgba(0,0,0,0.85);\n  backdrop-filter:blur(16px); -webkit-backdrop-filter:blur(16px);\n  display:flex; align-items:center; justify-content:center;\n  padding:24px;\n  animation:fadeIn 0.2s ease;\n}\n.authModal {\n  background:#0d0d0d;\n  border:1px solid rgba(255,255,255,0.1);\n  border-radius:24px; padding:40px;\n  width:100%; max-width:400px;\n  position:relative;\n  box-shadow:0 40px 100px rgba(0,0,0,0.8), 0 0 80px rgba(168,85,247,0.08);\n  animation:popIn 0.25s ease;\n}\n.authClose {\n  position:absolute; top:16px; right:16px;\n  font-size:17px; color:rgba(255,255,255,0.3);\n  padding:7px; border-radius:8px; transition:all 0.15s;\n}\n.authClose:hover { color:#fff; background:rgba(255,255,255,0.08); }\n.authLogo { display:flex; align-items:center; gap:8px; margin-bottom:24px; }\n.authLogoText { font-size:14px; font-weight:700; }\n.authTitle { font-size:24px; font-weight:800; letter-spacing:-0.03em; margin-bottom:8px; }\n.authSub { font-size:14px; color:rgba(255,255,255,0.4); margin-bottom:28px; }\n.authForm { display:flex; flex-direction:column; gap:12px; }\n.authInput {\n  background:rgba(255,255,255,0.05);\n  border:1px solid rgba(255,255,255,0.1);\n  border-radius:12px; padding:13px 16px;\n  color:#fff; font-size:15px; outline:none;\n  transition:border-color 0.2s, box-shadow 0.2s; width:100%;\n  letter-spacing:-0.01em;\n}\n.authInput:focus { border-color:rgba(168,85,247,0.5); box-shadow:0 0 0 3px rgba(168,85,247,0.1); }\n.authInput::placeholder { color:rgba(255,255,255,0.25); }\n.authErr { font-size:13px; color:#ff3b30; background:rgba(255,59,48,0.08); border:1px solid rgba(255,59,48,0.2); padding:10px 14px; border-radius:10px; }\n.authBtn {\n  background:var(--grad); background-size:300% 300%;\n  animation:gradFlow 5s ease infinite;\n  color:#fff; font-size:15px; font-weight:700;\n  padding:14px; border-radius:12px; width:100%;\n  transition:all 0.2s; display:flex; align-items:center; justify-content:center;\n}\n.authBtn:hover:not(.authBtnLoad) { transform:translateY(-1px); box-shadow:0 8px 30px rgba(168,85,247,0.4); }\n.authBtnLoad { background:rgba(255,255,255,0.1)!important; animation:none!important; }\n.authSwitch { font-size:13px; color:rgba(255,255,255,0.4); text-align:center; margin-top:20px; }\n.authSwitchBtn { color:#a855f7; font-size:13px; transition:color 0.15s; }\n.authSwitchBtn:hover { color:#c084fc; }\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   SPINNER\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n.spinner {\n  display:inline-block; width:16px; height:16px;\n  border:2px solid rgba(255,255,255,0.2);\n  border-top-color:#fff; border-radius:50%;\n  animation:spin 0.65s linear infinite;\n}\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   RESPONSIVE\n\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n@media(max-width:768px){\n  .nav { padding:12px 16px; }\n  .navLink { display:none; }\n  .hero { padding:120px 20px 80px; }\n  .heroCtas { flex-direction:column; align-items:stretch; }\n  .ctaPrimary,.ctaSecondary { text-align:center; }\n  .heroStats { gap:20px; }\n  .heroStatNum { font-size:22px; }\n  .featGrid { grid-template-columns:1fr 1fr; gap:10px; }\n  .pricingGrid { grid-template-columns:1fr; }\n  .cwChips { grid-template-columns:1fr; }\n  .chatMsgs { padding:14px; }\n  .msgBubble { max-width:88%; }\n  .chatInput { padding:10px 14px 16px; }\n  .toolBody { padding:14px; }\n  .genBtn { width:100%; }\n  .authModal { padding:28px 24px; }\n}\n@media(max-width:480px){\n  .featGrid { grid-template-columns:1fr; }\n  .heroTitle { font-size:36px; }\n}\n")
